const hora = new Date().getUTCHours();
let slot, tipo;

if (hora === 12) { slot = 'manana'; tipo = 'tip_tecnico'; }
else if (hora === 16) { slot = 'mediodia'; tipo = 'caso_uso'; }
else { slot = 'tarde'; tipo = 'thought_leadership'; }

