const N = temas_base.length; // 60 temas

// Slot offset so morning/midday/evening each use a different base index
const slotNum = slot === 'manana' ? 0 : slot === 'mediodia' ? 1 : 2;

// Empresa gets topic at (day + slotOffset) % N
// Personal gets a DIFFERENT topic at (day + slotOffset + 30) % N  (30 = half the catalog away)
const idxEmpresa  = (diasDesdeEpoch * 3 + slotNum) % N;
const idxPersonal = (diasDesdeEpoch * 3 + slotNum + 45) % N;

const temaBaseEmpresa  = temas_base[idxEmpresa];
const temaBasePersonal = temas_base[idxPersonal];

// Each account gets its own angle type — empresa gets the scheduled tipo, personal gets a different one
const tiposDisponibles = ['tip_tecnico', 'caso_uso', 'thought_leadership'];
const tipoPersonalIdx  = (tiposDisponibles.indexOf(tipo) + 1) % tiposDisponibles.length;
const tipoPersonal     = tiposDisponibles[tipoPersonalIdx];

const angulos = {
  tip_tecnico:        (t) => t + ' — controles a implementar, como y con que tecnologia',
  caso_uso:           (t) => t + ' — como se aborda en el sector: proceso, decision y resultado',
  thought_leadership: (t) => t + ' — por que importa hoy, riesgo de no actuar y enfoque ejecutivo'
};

const temaEmpresa  = angulos[tipo](temaBaseEmpresa);
const temaPersonal = angulos[tipoPersonal](temaBasePersonal);

return [{ json: {
  slot,
  tipo,
  tipoPersonal,
  tema:          temaEmpresa,
  tema_personal: temaPersonal,
  tema_base:     temaBaseEmpresa,
  tema_base_personal: temaBasePersonal,
  hora_utc: hora
} }];

const resp = $input.first().json;
const prev = $('Determinar Slot y Tema').first().json;

// Manejar error de API
if (resp.error || (!resp.content && !resp.choices)) {
  throw new Error('Limpiar GPT error: ' + (resp.error?.message || resp.msg || JSON.stringify(resp).substring(0,100)));
}

const raw = (resp.content?.[0]?.text || resp.choices?.[0]?.message?.content || '').trim();
let parsed;
try {
  const cleaned = raw.replace(/^```json\s*/i,'').replace(/^```\s*/i,'').replace(/\s*```$/i,'').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = { ideas_clave: [], datos_relevantes: [], insight_principal: '' };
}
return [{ json: {
  ...prev,
  ideas_clave: parsed.ideas_clave || [],
  datos_relevantes: parsed.datos_relevantes || [],
  insight_principal: parsed.insight_principal || ''
