const resp = $input.first().json;
const prev = $('Extraer Limpieza GPT').first().json;

// Manejar error de API
if (resp.error || (!resp.content && !resp.choices)) {
  throw new Error('Estructurar GPT error: ' + (resp.error?.message || resp.msg || JSON.stringify(resp).substring(0,100)));
}

const raw = (resp.content?.[0]?.text || resp.choices?.[0]?.message?.content || '').trim();
let parsed;
try {
  const cleaned = raw.replace(/^```json\s*/i,'').replace(/^```\s*/i,'').replace(/\s*```$/i,'').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = { hook: '', problema: '', insight: '', ancla_cuantitativa: '', ejemplo: '', recomendacion: '', cta: '' };
}
return [{ json: { ...prev, estructura: parsed } }];

const item = $input.first().json;

const raw = item?.content?.[0]?.text || item?.choices?.[0]?.message?.content || '';

// Strip markdown code fences
let cleaned = raw
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```\s*$/g, '')
  .trim();

// Repara saltos de línea literales dentro de strings JSON
function repairJSON(str) {
  let inString = false;
  let escaped  = false;
  let result   = '';
  for (let i = 0; i < str.length; i++) {
    const ch = str[i];
    if (escaped)                     { result += ch; escaped = false; continue; }
    if (ch === '\\' && inString)     { result += ch; escaped = true;  continue; }
    if (ch === '"')                  { inString = !inString; result += ch; continue; }
    if (inString && ch === '\n')     { result += '\\n'; continue; }
    if (inString && ch === '\r')     { result += '\\r'; continue; }
    if (inString && ch === '\t')     { result += '\\t'; continue; }
    result += ch;
  }
  return result;
}

// Extrae un campo incluso de JSON truncado
function extractField(str, field) {
  // JSON completo
  const full = new RegExp('"' + field + '"\\s*:\\s*"((?:[^"\\\\]|\\\\[\\s\\S])*)"');
  const m1 = str.match(full);
  if (m1) return m1[1];

  // JSON truncado — sin comilla de cierre
  const trunc = new RegExp('"' + field + '"\\s*:\\s*"([\\s\\S]*)$');
  const m2 = str.match(trunc);
  if (m2) return m2[1].replace(/"\s*,?\s*"image_prompt[\s\S]*$/, '').trim();

  return null;
}

let parsed;

// Intento 1: parse directo
try {
  parsed = JSON.parse(cleaned);
} catch(e1) {

  // Intento 2: reparar saltos de línea y parsear
  try {
    parsed = JSON.parse(repairJSON(cleaned));
  } catch(e2) {

    // Intento 3: cerrar JSON truncado y parsear
    try {
      let fixed = repairJSON(cleaned).trimEnd();
      if (!fixed.endsWith('"') && !fixed.endsWith('}')) fixed += '"';
      if (!fixed.endsWith('}')) fixed += '\n}';
      parsed = JSON.parse(fixed);
    } catch(e3) {

      // Intento 4: extracción por regex campo a campo
      const repaired   = repairJSON(cleaned);
      const postText   = extractField(repaired, 'post_text');
      const imagePrompt = extractField(repaired, 'image_prompt');

      if (!postText) {
        throw new Error(`Parse error Claude dual: ${cleaned.substring(0, 200)}`);
      }
      parsed = {
        post_text:    postText.replace(/\\n/g, '\n'),
        image_prompt: imagePrompt || ''
      };
    }
  }
}

// Extract both posts and both image prompts
const basePrompt = parsed.image_prompt || '';
const postEmpresa  = parsed.post_empresa  || parsed.post_text || '';
const postPersonal = parsed.post_personal || parsed.post_text || '';
const promptEmpresa  = parsed.image_prompt_empresa  || basePrompt + ', enterprise IT consulting corporate visual';
const promptPersonal = parsed.image_prompt_personal || basePrompt + ', executive personal thought leadership visual';

return [{ json: {
  post_text:            postEmpresa,
  post_empresa:         postEmpresa,
  post_personal:        postPersonal,
  image_prompt_empresa: promptEmpresa,
  image_prompt_personal: promptPersonal,
