  _tema:        item._tema,
  _tema_personal: item._tema_personal,
  _tema_base:   item._tema_base,
  _tema_base_personal: item._tema_base_personal,
  _tipo:        item._tipo,
  _tipoPersonal: item._tipoPersonal,
  _formato:     item._formato
}}];

