  throw new Error('Imagen empresa no lista aun — estado: ' + (state || '?'));
}
let rj;
try { rj = typeof resultRaw === 'string' ? JSON.parse(resultRaw) : resultRaw; }
catch(e) { throw new Error('resultJson invalido empresa'); }
const imageUrl = rj?.resultUrls?.[0] || rj?.url || rj?.imageUrl;
if (!imageUrl) throw new Error('Sin URL imagen empresa');
const prev = $('Extraer Task ID Empresa').first().json;
